import smile.identity.core.IDApi;
import java.nio.file.Files;
import java.nio.file.Paths;
import java.io.IOException;
import java.util.ArrayList;
import java.util.HashMap;
import java.util.List;
import java.util.Map;
import smile.identity.core.WebApi;
import io.github.cdimascio.dotenv.Dotenv;
import smile.identity.core.models.ImageDetail;
import smile.identity.core.models.PartnerParams;
import smile.identity.core.models.Options;
import smile.identity.core.enums.ImageType;
import smile.identity.core.enums.JobType;

public class SmartSelfieAuthentication {

    public static void main(String[] args) {

        // Load credentials from environment variables
        Dotenv dotenv = Dotenv.configure().ignoreIfMissing().load();

        String partnerId = dotenv.get("SMILE_PARTNER_ID", "1335");
        String defaultCallback = "https://webhook.site/be0a1061-37cc-4eb5-abbe-45faa5795d2c";
        String apiKey = dotenv.get("SMILE_API_KEY", "43608984-f548-4fe0-9af2-1a1bec0604a0");
        String sidServer = dotenv.get("SMILE_SID_SERVER", "0");  // Use '0' for the sandbox server and '1' for production

        WebApi connection = new WebApi(partnerId, apiKey, defaultCallback, sidServer);

        // Generate unique IDs using timestamp
        String timestamp = String.valueOf(System.currentTimeMillis());
        String uniqueUserId = "test-auth-" + timestamp;
        String uniqueJobId = "job-" + timestamp;

        // Create required tracking parameters
        Map<String, Object> optionalInfo = new HashMap(); // map of optional parameters partner uses to track jobs. can be left empty
        PartnerParams params = new PartnerParams(JobType.SMART_SELFIE_REGISTRATION, uniqueUserId, uniqueJobId, optionalInfo);

        // Create image list
        // ImageType - This infers to either a file or a base64 encoded image, but not both.
        // If using base 64 encoded image, pass in the encoded string as the second parameter and set fileName to null.
        // If using file, set image parameter to null and filename to path to file
        // ImageType.SELFIE - Selfie image jpg or png (if you have the full path of the selfie)
        // ImageType.SELFIE_BASE64 - Selfie image jpg or png base64 encoded (if you have the base64image string of the selfie)
        // ImageType.LIVENESS - Liveness image jpg or png (if you have the full path of the liveness image)
        // ImageType.LIVENESS_BASE64 - Liveness image jpg or png base64 encoded (if you have the base64image string of the liveness image)


        List<ImageDetail> imageDetails = new ArrayList<>();
        // ImageDetail selfie = new ImageDetail(ImageType.SELFIE, null, "< full path to selfie >");
        // ImageDetail liveness = new ImageDetail(ImageType.LIVENESS, null, "< full path to liveness image");


        // Load base64 image from external file to avoid Java string literal size limit
        String selfieBase64 = "";
        try {
            selfieBase64 = new String(java.nio.file.Files.readAllBytes(java.nio.file.Paths.get("resources/selfie_base64.txt")));
        } catch (java.io.IOException e) {
            System.err.println("Error reading selfie base64 file: " + e.getMessage());
        }
        ImageDetail selfie = new ImageDetail(ImageType.SELFIE_BASE64, selfieBase64, null);
        // imageDetails.add(liveness); // Not required if you don't require proof of life

        ImageDetail liveness1 = new ImageDetail(ImageType.LIVENESS_BASE64, "", null);
        ImageDetail liveness2 = new ImageDetail(ImageType.LIVENESS_BASE64, "", null);
        ImageDetail liveness3 = new ImageDetail(ImageType.LIVENESS_BASE64, "", null);
        ImageDetail liveness4 = new ImageDetail(ImageType.LIVENESS_BASE64, "", null);
        ImageDetail liveness5 = new ImageDetail(ImageType.LIVENESS_BASE64, "", null);       
        ImageDetail liveness6 = new ImageDetail(ImageType.LIVENESS_BASE64, "", null);
        ImageDetail liveness7 = new ImageDetail(ImageType.LIVENESS_BASE64, "", null); // Not required if you don't required

        imageDetails.add(selfie);
        imageDetails.add(liveness1);
        imageDetails.add(liveness2);
        imageDetails.add(liveness3);
        imageDetails.add(liveness4);
        imageDetails.add(liveness5);
        imageDetails.add(liveness6); 
        imageDetails.add(liveness7);// Not required if you don't required
        

        // Options for the job
        boolean returnJobStatus = true; // Set to true if you want to get
        // the job result in sync (in addition to the result been sent to
        // your callback). If set to false, result is sent to callback url only
        boolean returnHistory = false; // Set to true to receive all of the
        // updates you would otherwise have received in your callback as
        // opposed to only the final result. You must set return_job_status
        // to true to use this flag.
        boolean returnImageLinks = false; // Set to true to receive links to
        // the selfie and the photo it was compared to. You must set
        // return_job_status to true to use this flag.
        String callBackUrl = "< optional callback url to use for this job only >";
        Options options = new Options(returnHistory, returnImageLinks, returnJobStatus, callBackUrl);

        try {
            System.out.println("Submitting job for Smart Selfie Authentication...");
            connection.submitJob(params, imageDetails, null, options);
            System.out.println("Job submitted successfully!");
        } catch (Exception e) {
            System.err.println("Error submitting job: " + e.getMessage());
            e.printStackTrace();
        }


    }
}
